SELECT count(1)
FROM agent_commission_grant_record a


        AND a.grant_time  >=  #{vo.grantStartTime}


        AND a.grant_time  <=  #{vo.grantEndTime}


        AND  a.agent_account =  #{vo.agentAccount}


        AND  a.site_code =  #{vo.siteCode}


        AND  a.agent_type =  #{vo.agentType}


        AND  a.agent_category =  #{vo.agentCategory}


        AND  a.commission_type =  #{commissionType}

select sum(commission_amount) from agent_commission_review_record
where agent_id = #{agentId}
 and order_status = 3
